  </div>
</main>

<script>
  // ── SSE state subscription ──────────────────────────────────────────────────
  let sseConnected = false;

  function connectSSE() {
    const es = new EventSource('/events');

    es.onmessage = (e) => {
      const data = JSON.parse(e.data);
      sseConnected = true;
      updateConnStatus();

      // Update state bar
      document.getElementById('mapLabel').textContent    = data.map_name    || data.map_id    || '—';
      document.getElementById('posLabel').textContent    = data.pos         || '—';
      document.getElementById('hpLabel').textContent     = data.player_hp   || '—';
      document.getElementById('battleLabel').textContent = data.battle      ? 'YES ⚔'         : 'no';

      // Status dot
      const dot = document.getElementById('statusDot');
      dot.className = 'status-dot';
      if (data.battle)        dot.classList.add('battle');
      else if (data.dialog_open) dot.classList.add('dialog');
      else if (data.map_id)   dot.classList.add('playing');

      document.getElementById('statusText').textContent =
        data.battle ? '⚔ IN BATTLE' :
        data.dialog_open ? '💬 DIALOG' :
        data.map_id ? 'playing' : 'idle';
    };

    es.onerror = () => {
      sseConnected = false;
      updateConnStatus();
      setTimeout(connectSSE, 3000);
    };

    es.onopen = () => {
      sseConnected = true;
      updateConnStatus();
    };
  }

  function updateConnStatus() {
    const el = document.getElementById('connStatus');
    if (sseConnected) {
      el.textContent = 'SSE: ✓';
      el.className = 'connection-status connected';
    } else {
      el.textContent = 'SSE: ✗';
      el.className = 'connection-status disconnected';
    }
  }

  connectSSE();

  // ── Image refresh ─────────────────────────────────────────────────────────
  let streamActive = true;

  function refreshImg() {
    if (streamActive) {
      const img = document.getElementById('gameImg');
      img.src = '/api/agent/screenshot?' + Date.now();
      img.onerror = () => { img.src = '/api/agent/screenshot?' + Date.now(); };
    }
    setTimeout(refreshImg, 2000);
  }
  refreshImg();

  // ── Instructions ──────────────────────────────────────────────────────────
  let myInstructions = [];

  function loadInstructions() {
    fetch('/api/queue')
      .then(r => r.json())
      .then(data => {
        if (data.count > 0 && data.commands.join(',') !== myInstructions.join(',')) {
          myInstructions = data.commands;
          renderInstructions(data.commands);
        }
      })
      .catch(() => {});
  }

  function renderInstructions(cmds) {
    const list = document.getElementById('instrList');
    if (cmds.length === 0) return;

    list.innerHTML = cmds.map((cmd, i) => `
      <div class="instr-item">
        <div class="timestamp">#${i + 1}</div>
        <div class="text">${escapeHtml(cmd)}</div>
      </div>
    `).join('');

    // Auto-scroll panel
    const panel = document.getElementById('instrPanel');
    panel.scrollTop = panel.scrollHeight;
  }

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // Poll queue every 2s
  setInterval(loadInstructions, 2000);

  // ── Send ─────────────────────────────────────────────────────────────────
  function sendInstruction() {
    const input = document.getElementById('cmdInput');
    const text = input.value.trim();
    if (!text) return;

    fetch('/api/command', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({text})
    })
    .then(r => r.json())
    .then(() => {
      input.value = '';
      loadInstructions();
    })
    .catch(err => alert('Failed to send: ' + err));
  }

  document.getElementById('sendBtn').addEventListener('click', sendInstruction);
  document.getElementById('cmdInput').addEventListener('keydown', (e) => {
    if (e.key === 'Enter') sendInstruction();
  });
</script>

</body>
